```cpp
#pragma once

#include <reaction/reaction.h>
#include <tuple>

namespace test_reaction {

// ============================================
// Function implementations
// ============================================

/**
 * Function: Test batch execution reduces recomputation count
 *
 * @param initialA Initial value for variable a
 * @param initialB Initial value for variable b
 * @param nonBatchA Value to set a without batching
 * @param nonBatchB Value to set b without batching
 * @param batchA Value to set a within batch
 * @param batchB Value to set b within batch
 * @return std::tuple<int, int, int> {final sum, count after non-batch updates, count after batch updates}
 */
std::tuple<int, int, int> test_batch_execution(int initialA,
                                               int initialB,
                                               int nonBatchA,
                                               int nonBatchB,
                                               int batchA,
                                               int batchB) {
    // 1. Create reactive variables for a and b using reaction::var
    auto a = reaction::var(initialA);
    auto b = reaction::var(initialB);

    // 2. Create reactive variable for recompute count using reaction::var
    auto recomputeCount = reaction::var(0);

    // 3. Create calculation that sums a and b and increments recompute count using reaction::calc
    auto sumCalc = reaction::calc([&recomputeCount](int a_val, int b_val) {
        // Increment recompute count by getting current value and adding 1
        recomputeCount.value(recomputeCount.get() + 1);
        return a_val + b_val;
    }, a, b);

    // 4. Perform non-batch updates using value() method
    a.value(nonBatchA);
    b.value(nonBatchB);

    // 5. Record recompute count after non-batch updates using get() method
    int countAfterNonBatch = recomputeCount.get();

    // 6. Create batch context using reaction::batch and set values within batch
    auto batchContext = reaction::batch([&a, &b, batchA, batchB]() {
        a.value(batchA);
        b.value(batchB);
    });

    // 7. Execute batch using execute() method
    batchContext.execute();

    // 8. Record recompute count after batch updates using get() method
    int countAfterBatch = recomputeCount.get();

    // 9. Return final sum and counts
    return std::make_tuple(sumCalc.get(), countAfterNonBatch, countAfterBatch);
}

}  // namespace test_reaction
```

## Key Implementation Details:

1. **Reactive Variables**: Created using `reaction::var` with initial values
2. **Recompute Count**: Uses `reaction::var(0)` to track calculation executions
3. **Calculation**: Uses `reaction::calc` with a lambda that increments the recompute count and returns the sum
4. **Non-Batch Updates**: Direct calls to `value()` method trigger immediate recalculations
5. **Batch Context**: Uses `reaction::batch` to defer updates until `execute()` is called
6. **Value Access**: Uses `get()` method to retrieve current values from reactive variables

This implementation demonstrates the performance benefits of batch execution by showing how non-batch updates trigger immediate recalculations, while batch updates defer them until execution, reducing the total recompute count.

