```cpp
#pragma once

#include <reaction/reaction.h>

namespace test_reaction {

// ============================================
// Helper types
// ============================================

class RecordingNode : public reaction::ObserverNode {
public:
    void valueChanged(bool changed = true) override {
        m_notifications++;
    }

    int notificationCount() const {
        return m_notifications;
    }

private:
    int m_notifications = 0;
};

struct RollbackObservation {
    int notificationsAfterSecondBinding;
    int notificationsAfterRollback;
};

// ============================================
// Function implementation
// ============================================

RollbackObservation test_observer_state_rollback() {
    REACTION_REGISTER_THREAD();

    // 1. Create two RecordingNode instances
    RecordingNode sensor1;
    RecordingNode sensor2;

    // 2. Get ObserverGraph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // 3. Register both nodes with the graph
    graph.addNode(&sensor1);
    graph.addNode(&sensor2);

    // 4. Set up initial dependency: sensor1 observes sensor2
    graph.addObserver(&sensor1, &sensor2);

    // 5. Save the current state of sensor1 for rollback
    auto rollbackFunc = graph.saveNodeStateForRollback(&sensor1);

    // 6. Transactional update: sensor1 observes sensor2 and sensor2 observes sensor1
    graph.updateObserversTransactional(&sensor1, {&sensor2});
    graph.updateObserversTransactional(&sensor2, {&sensor1});

    // 7. Trigger notification on sensor2
    sensor2.notify(true);

    // 8. Record notification count after second binding
    int countAfterSecondBinding = sensor1.notificationCount();

    // 9. Execute rollback
    rollbackFunc();

    // 10. Trigger notification on sensor1
    sensor1.notify(true);

    // 11. Record notification count after rollback
    int countAfterRollback = sensor1.notificationCount();

    // 12. Return the struct with both recorded values
    return RollbackObservation{
        .notificationsAfterSecondBinding = countAfterSecondBinding,
        .notificationsAfterRollback = countAfterRollback
    };
}

}  // namespace test_reaction
