    // 1. Create a reactive variable using reaction::var with initial value
    auto reactiveVar = reaction::var(initialValue);

    // 2. Create a counter variable to track recomputation count
    int counter = 0;

    // 3. Create an AlwaysTrig calculation using reaction::calc that doubles the value and increments counter
    auto calculation = reaction::calc<reaction::AlwaysTrig>(
        [&counter](int value) {
            counter++;  // Increment counter on each recomputation
            return value * 2;  // Double the value
        },
