    );

    // 4. Store current recompute count after initialization
    int countAfterInit = counter;

    // 5. Use value() method to write the same value back to the reactive variable
    reactiveVar.value(initialValue);

    // 6. Store recompute count after duplicate write
    int countAfterDuplicateWrite = counter;

    // 7. Force evaluation to avoid unused variable warnings
    int result = calculation();

    // 8. Return result with recompute counts
    return {countAfterInit, countAfterDuplicateWrite};
}

}  // namespace test_reaction
```

