1. **Thread Manager Access**: Uses `reaction::ThreadManager::getInstance()` to get the singleton instance
2. **State Reset**: Calls `resetForTesting()` to clear thread registration state
3. **Mutex Creation**: Creates `reaction::ConditionalSharedMutex` instance
4. **Lock Operations**: Uses `try_lock_shared()` and `try_lock()` for shared/exclusive locking
5. **RAII Guards**: Employs `ConditionalSharedLockGuard` for automatic lock management
6. **Thread Safety**: Enables thread safety mode using `enableThreadSafety(true)`
7. **Result Struct**: Returns all test results in the specified `SharedMutexResult` structure

The implementation follows the exact sequence specified in the assessment objectives, properly handling both safety modes and demonstrating the behavior of conditional mutexes in different threading scenarios.

output.result:
#pragma once

#include <reaction/concurrency/thread_manager.h>
#include <reaction/concurrency/thread_manager.h> // Additional include for ConditionalSharedMutex

namespace test_reaction {

struct SharedMutexResult {
    bool trySharedWithoutSafety;
    bool tryUniqueWhileSharedWithoutSafety;
    bool trySharedWithSafety;
    bool tryUniqueWhileSharedWithSafety;
};

SharedMutexResult test_conditional_shared_mutex() {
    // 1. Get thread manager instance
    auto& threadManager = reaction::ThreadManager::getInstance();

    // 2. Reset thread manager state
    threadManager.resetForTesting();

    // 3. Create ConditionalSharedMutex instance
    reaction::ConditionalSharedMutex mutex;

    // 4. Attempt to acquire shared lock without safety
    bool trySharedWithoutSafety = mutex.try_lock_shared();

    // 5. Unlock shared lock if acquired
    if (trySharedWithoutSafety) {
        mutex.unlock_shared();
    }

    bool tryUniqueWhileSharedWithoutSafety = false;

    // 6. Create ConditionalSharedLockGuard in a scope block
    {
        reaction::ConditionalSharedLockGuard<reaction::ConditionalSharedMutex> guard(mutex);

        // 7. Attempt to acquire unique lock while shared lock is held without safety
        tryUniqueWhileSharedWithoutSafety = mutex.try_lock();

        // 8. Unlock unique lock if acquired
        if (tryUniqueWhileSharedWithoutSafety) {
            mutex.unlock();
        }
    } // 9. Exit guard scope (automatic unlock via RAII)

    // 10. Enable thread safety
    threadManager.enableThreadSafety(true);

    // 11. Attempt to acquire shared lock with safety
    bool trySharedWithSafety = mutex.try_lock_shared();

    // 12. Unlock shared lock if acquired
    if (trySharedWithSafety) {
        mutex.unlock_shared();
    }

    bool tryUniqueWhileSharedWithSafety = false;

    // 13. Create ConditionalSharedLockGuard in a scope block again
    {
        reaction::ConditionalSharedLockGuard<reaction::ConditionalSharedMutex> guard(mutex);

        // 14. Attempt to acquire unique lock while shared lock is held with safety
        tryUniqueWhileSharedWithSafety = mutex.try_lock();

        // 15. Unlock unique lock if acquired
        if (tryUniqueWhileSharedWithSafety) {
            mutex.unlock();
        }
    } // 16. Exit guard scope (automatic unlock via RAII)

    // 17. Return shared mutex result
    return SharedMutexResult{
        trySharedWithoutSafety,
        tryUniqueWhileSharedWithoutSafety,
        trySharedWithSafety,
        tryUniqueWhileSharedWithSafety
    };
}

}  // namespace test_reaction

