    using namespace reaction::memory;

    StackAllocationSnapshot snapshot{};

    // 1. Disable monitoring
    StackMonitor::setMonitoringEnabled(false);

    // 2. Initialize stack monitor
    StackMonitor::initialize();

    // 3. Check allocation without monitoring
    snapshot.smallAllowedWithoutMonitoring = StackMonitor::canAllocate(10);
    snapshot.largeAllowedWithoutMonitoring = StackMonitor::canAllocate(1000);
    snapshot.runtimeAllowedWithoutMonitoring = StackMonitor::canAllocate(largeSize);

    // 4. Enable monitoring
    StackMonitor::setMonitoringEnabled(true);

    // 5. Initialize stack monitor again
    StackMonitor::initialize();

